import { useTheme } from '../contexts/ThemeContext';
import { Sun, Moon } from 'lucide-react';

const ThemeToggle = () => {
  const { isDark, toggleTheme } = useTheme();

  return (
    <button
      onClick={toggleTheme}
      className="inline-flex items-center justify-center w-10 h-10 rounded-2xl border border-slate-200/80 bg-white/80 text-slate-600 shadow-sm transition-all duration-200 hover:bg-white dark:border-slate-700/80 dark:bg-slate-900/80 dark:text-slate-300 hover:text-slate-900 dark:hover:text-white hover:shadow-md"
      title={isDark ? "Switch to light mode" : "Switch to dark mode"}
      aria-label="Toggle dark mode"
    >
      {isDark ? <Sun className="w-5 h-5" /> : <Moon className="w-5 h-5" />}
    </button>
  );
};

export default ThemeToggle;
